import requests

class GitHubAPI:
    def __init__(self, token):
        self.token = token

    def get_repositories(self, username):
        url = f'https://api.github.com/users/{username}/repos'
        headers = {'Authorization': f'token {self.token}'}
        response = requests.get(url, headers=headers)
        repositories = response.json()
        return repositories

    def print_repository_info(self, repositories):
        for repository in repositories:
            print(f"Name: {repository['name']}")
            print(f"Stars: {repository['stargazers_count']}")
            print(f"Last Update: {repository['updated_at']}")
            print('')

def main():
    token = 'your-github-token'
    username = 'your-username'
    api = GitHubAPI(token)
    repositories = api.get_repositories(username)
    api.print_repository_info(repositories)

if __name__ == "__main__":
    main()
